const fs = require('fs');
const path = '/home/node/demo-data/leads_batch_import.csv';
const fallback = [
  { name: 'Elon Musk', email: 'elon@tesla.com', company: 'Tesla', company_size: 100000, message: 'Need AI for data processing.', source: 'csv_demo' },
  { name: 'Bill Gates', email: 'bill@microsoft.com', company: 'Microsoft', company_size: 200000, message: 'Partnership for AI ethics.', source: 'csv_demo' },
  { name: 'Random User', email: 'random@gmail.com', company: 'None', company_size: 0, message: 'Just saying hi.', source: 'csv_demo' }
];
let rows = [];
try {
  const raw = fs.readFileSync(path, 'utf8');
  const lines = raw.trim().split(/\r?\n/);
  for (let i = 1; i < lines.length; i++) {
    const parts = lines[i].split(',');
    if (parts.length < 5) continue;
    rows.push({
      name: parts[0].trim(),
      email: parts[1].trim().toLowerCase(),
      company: parts[2].trim(),
      company_size: parseInt(parts[3], 10) || 0,
      message: parts.slice(4).join(',').trim(),
      source: 'csv_demo'
    });
  }
} catch (e) {
  rows = fallback;
}
return rows.map((r) => ({ json: r }));
